/* ============ STATE ============ */
let state, user=null, filters={collection:"",surface:"",country:"",size:"",featured:false}, currentView="showroom", manageTab="designs", searchQ="";
let spotTimer=null, spotIdx=0, spotList=[];
function loadState(){
  const raw=Store.get("ojm_state");
  if(raw){try{state=JSON.parse(raw);}catch(e){state=seed();}}
  else state=seed();
  if(!state.users||!state.users.length)state.users=DEFAULT_USERS.map(u=>({...u}));
}
function save(){Store.set("ojm_state",JSON.stringify(state));if(fbReady&&!applyingCloud)cloudPush();}
function uid(p){return p+Date.now().toString(36)+Math.floor(Math.random()*999).toString(36);}

/* ============ HELPERS ============ */
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
const esc=s=>String(s).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]));
const collName=id=>(state.collections.find(c=>c.id===id)||{}).name||"—";
const dById=id=>state.designs.find(d=>d.id===id);
function toast(msg){const t=$("#toast");$("#toastMsg").textContent=msg;t.classList.add("show");clearTimeout(t._t);t._t=setTimeout(()=>t.classList.remove("show"),2200);}
function can(v){return user&&PERMS[user.role].includes(v);}
function basketQty(){return state.basket.reduce((s,b)=>s+b.qty,0);}

/* ============ AUTH ============ */
function tryLogin(){
  const u=$("#lu").value.trim().toLowerCase(),p=$("#lp").value;
  const rec=state.users.find(x=>x.key===u);
  if(!rec||rec.pass!==p){$("#lerr").textContent="Invalid username or password.";return;}
  user={...rec};
  Store.set("ojm_user",u);
  $("#lerr").textContent="";
  enterApp();
}
function enterApp(){
  $("#login").style.display="none";$("#app").style.display="block";
  $("#avatar").textContent=initOf(user);$("#uname").textContent=user.name;$("#urole").textContent=user.role;
  buildNav();go(can("showroom")?"showroom":"projects");
  refreshCounts();
}
function logout(){user=null;Store.set("ojm_user","");$("#app").style.display="none";$("#login").style.display="grid";$("#lu").value="";$("#lp").value="";}

